import{_ as a,o as t,c as o,a6 as s}from"./chunks/framework.wLlb4ebq.js";const u=JSON.parse('{"title":"SyncState V1/V2 迁移","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/syncstate-migration.md","filePath":"concepts/syncstate-migration.md"}'),i={name:"concepts/syncstate-migration.md"};function c(d,e,r,n,l,h){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="syncstate-v1-v2-迁移" tabindex="-1">SyncState V1/V2 迁移 <a class="header-anchor" href="#syncstate-v1-v2-迁移" aria-label="Permalink to “SyncState V1/V2 迁移”">​</a></h1><p>v3.7.0 完成了 SyncState 从 V1 嵌套结构到 V2 扁平结构的迁移，消除了 V1/V2 双写问题，并引入 V1 facade 保证向后兼容。</p><h2 id="为什么要迁移" tabindex="-1">为什么要迁移 <a class="header-anchor" href="#为什么要迁移" aria-label="Permalink to “为什么要迁移”">​</a></h2><p>旧版 SyncState 使用嵌套结构存储同步状态：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>V1: { linuxdo: {...}, github: { meta, stars, repos, forks, gists }, bookmarks: {...} }</span></span></code></pre></div><p>这带来了两个问题：</p><ol><li><strong>V1/V2 双写</strong>：新代码写 V2 格式，旧代码仍写 V1 格式，导致数据不一致。</li><li><strong>GitHub 子类型嵌套</strong>：<code>github.stars</code>、<code>github.repos</code> 等子类型嵌套在同一对象下，无法独立管理同步周期。</li></ol><h2 id="v2-扁平结构" tabindex="-1">V2 扁平结构 <a class="header-anchor" href="#v2-扁平结构" aria-label="Permalink to “V2 扁平结构”">​</a></h2><p>V2 将所有来源类型展平为独立 key：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>V2: { version: 2, sources: { linuxdo: {...}, github-stars: {...}, github-repos: {...}, github-forks: {...}, github-gists: {...}, github-meta: {...}, bookmark: {...}, rss: {...}, zhihu: {...}, generic: {...} } }</span></span></code></pre></div><p>每个来源类型独立管理自己的 <code>lastSyncTime</code>、<code>lastSyncCount</code>、<code>lastError</code> 等字段。</p><h2 id="自动迁移" tabindex="-1">自动迁移 <a class="header-anchor" href="#自动迁移" aria-label="Permalink to “自动迁移”">​</a></h2><p>首次访问时，<code>SyncStateV2._load()</code> 检测到 V1 数据后自动执行 <code>_migrateV1toV2()</code>：</p><ul><li>将 <code>github.meta/stars/repos/forks/gists</code> 展平为 <code>github-meta/github-stars/...</code>。</li><li>将 <code>bookmarks</code> 重命名为 <code>bookmark</code>（单数形式，与其他来源类型一致）。</li><li>迁移是幂等的，重复执行不会产生副作用。</li></ul><h2 id="v1-facade" tabindex="-1">V1 facade <a class="header-anchor" href="#v1-facade" aria-label="Permalink to “V1 facade”">​</a></h2><p>为了消除双写，V1 的公共 API 被替换为 V2 的 facade 代理层。所有现有代码调用 <code>SyncState.getLinuxDoState()</code>、<code>SyncState.updateGitHubState()</code> 等方法时，实际委托给 <code>SyncStateV2</code>：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SyncState.getLinuxDoState() → SyncStateV2.getSourceState(&quot;linuxdo&quot;)</span></span>
<span class="line"><span>SyncState.updateGitHubState(subtype, data) → SyncStateV2.updateSourceState(&quot;github-&quot; + subtype, data)</span></span></code></pre></div><p>这样，旧代码无需修改即可自动使用 V2 存储。</p><h2 id="写入优化" tabindex="-1">写入优化 <a class="header-anchor" href="#写入优化" aria-label="Permalink to “写入优化”">​</a></h2><h3 id="queuemicrotask-合并" tabindex="-1">queueMicrotask 合并 <a class="header-anchor" href="#queuemicrotask-合并" aria-label="Permalink to “queueMicrotask 合并”">​</a></h3><p><code>SyncStateV2._save()</code> 使用 <code>queueMicrotask</code> 将同一事件循环 tick 内的多次写入合并为一次 <code>GM_setValue</code> 调用，减少 IPC 开销。回退链：<code>queueMicrotask</code> → <code>setTimeout(flush, 0)</code> → 同步写入。</p><h3 id="dedupstore-批量模式" tabindex="-1">DedupStore 批量模式 <a class="header-anchor" href="#dedupstore-批量模式" aria-label="Permalink to “DedupStore 批量模式”">​</a></h3><p><code>DedupStore</code> 支持 <code>beginBatch(sourceType)</code> / <code>endBatch()</code> 批量模式。批量模式下，<code>isDuplicate</code> 和 <code>markSeen</code> 只操作内存缓存，<code>endBatch()</code> 时一次性写入 <code>GM_setValue</code>。<code>SyncCoordinator.sync()</code> 在同步循环中使用批量模式，避免每条记录都触发 IPC。</p><h2 id="遗留问题" tabindex="-1">遗留问题 <a class="header-anchor" href="#遗留问题" aria-label="Permalink to “遗留问题”">​</a></h2><p>V1 facade 代理了 V2 的私有方法（<code>_clone</code>、<code>_load</code>、<code>_save</code>），破坏了封装。外部代码可能通过 V1 facade 访问 V2 内部实现。建议：</p><ol><li>移除 V1 facade 中对 V2 私有方法的代理。</li><li>将需要外部访问的方法提升为 V2 的公共 API。</li><li>或将 V1 facade 标记为 <code>@deprecated</code>，引导调用方迁移到 V2。</li></ol>`,26)])])}const b=a(i,[["render",c]]);export{u as __pageData,b as default};
